import React, { useState, useEffect } from 'react';
import { useAuth } from '../context/AuthContext';
import { api } from '../services/api';
import ModalNuevaSucursal from './ModalNuevaSucursal';
import { PlusCircle } from 'lucide-react'; // Opcional: para un icono lindo

const Dashboard = () => {
    const { user } = useAuth();
    const [locales, setLocales] = useState([]);
    const [loading, setLoading] = useState(true);
    const [modalAbierto, setModalAbierto] = useState(false); // <--- Control manual

    useEffect(() => {
        if (user?.id) fetchLocales();
    }, [user?.id]);

    const fetchLocales = async () => {
        try {
            const data = await api.getLocalesVendedor(user.id);
            setLocales(data);
        } catch (error) {
            console.error("Error cargando locales:", error);
        } finally {
            setLoading(false);
        }
    };

    const manejarNuevaSucursal = async (nuevaData) => {
        try {
            const creado = await api.crearLocal(nuevaData);
            setLocales([...locales, creado]);
            setModalAbierto(false); // Cerrar después de crear
        } catch (error) {
            alert("Error al crear sucursal");
        }
    };

    if (loading) return <div style={{ padding: '20px' }}>Cargando tus comercios...</div>;

    return (
        <div style={{ padding: '20px', maxWidth: '1200px', margin: '0 auto' }}>
            <div style={headerStyle}>
                <h1>Mis Locales</h1>
                {/* BOTÓN MANUAL PARA ABRIR EL FORMULARIO */}
                <button 
                    onClick={() => setModalAbierto(true)} 
                    style={btnNuevoEstilo}
                >
                    <PlusCircle size={20} />
                    Agregar Nueva Sucursal
                </button>
            </div>

            {/* Solo se muestra si el estado es true */}
            {modalAbierto && (
                <ModalNuevaSucursal 
                    onSave={manejarNuevaSucursal} 
                    onClose={() => setModalAbierto(false)} 
                />
            )}

            {locales.length === 0 ? (
                <div style={emptyStateStyle}>
                    <p>Aún no tienes sucursales registradas.</p>
                    <p style={{ fontSize: '0.9rem', color: '#64748b' }}>Haz clic en el botón superior para empezar.</p>
                </div>
            ) : (
                <div style={gridEstilo}>
                    {locales.map(local => (
                        <div key={local._id} style={cardEstilo}>
                            <h3 style={{ margin: '0 0 10px 0' }}>{local.nombre}</h3>
                            <p style={{ color: '#64748b', fontSize: '0.9rem' }}>{local.direccion}</p>
                            <button 
                                style={btnGestionar}
                                onClick={() => window.location.href=`/ofertas/${local._id}`}
                            >
                                Gestionar Ofertas
                            </button>
                        </div>
                    ))}
                </div>
            )}
        </div>
    );
};

// --- Estilos Actualizados ---
const headerStyle = { 
    display: 'flex', 
    justifyContent: 'space-between', 
    alignItems: 'center', 
    marginBottom: '30px',
    borderBottom: '2px solid #f1f5f9',
    paddingBottom: '15px'
};

const btnNuevoEstilo = {
    display: 'flex',
    alignItems: 'center',
    gap: '8px',
    background: '#2563eb',
    color: 'white',
    border: 'none',
    padding: '10px 20px',
    borderRadius: '8px',
    cursor: 'pointer',
    fontWeight: 'bold'
};

const btnGestionar = {
    marginTop: '15px',
    width: '100%',
    padding: '8px',
    background: '#1e293b',
    color: 'white',
    border: 'none',
    borderRadius: '6px',
    cursor: 'pointer'
};

const emptyStateStyle = {
    textAlign: 'center',
    padding: '50px',
    background: '#f8fafc',
    borderRadius: '12px',
    border: '2px dashed #cbd5e1',
    marginTop: '20px'
};

const gridEstilo = { display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(280px, 1fr))', gap: '20px' };
const cardEstilo = { background: 'white', border: '1px solid #e2e8f0', padding: '20px', borderRadius: '12px', boxShadow: '0 4px 6px -1px rgba(0,0,0,0.1)' };

export default Dashboard;
